+/** Process a target-specific relation event without collapsing it to the relation trait. */
+export function checkQueryPairTracking(
+    world: World,
+    query: QueryInstance,
+    entity: Entity,
+    eventType: EventType,
+    relationTrait: Trait,
+    target: Entity
+): boolean {
+    const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
+    if (!instance) return false;
+    // This performs the regular static and trait-tracking checks. Pair groups have no bitmasks.
+    if (!checkQueryTracking(world, query, entity, eventType, instance.generationId, instance.bitflag)) return false;
+
+    const targetId = getEntityId(target);
+    let hasOr = false;
+    let anyOr = false;
+    for (const group of query.trackingGroups) {
+        if (!group.pairs.length) continue;
+        const matchingPairs = group.pairs.filter((pair) => {
+            const pairCtx = pair[$internal];
+            return pairCtx.relation[$internal].trait === relationTrait &&
+                (pairCtx.target === '*' || pairCtx.target === target);
+        });
+        if (matchingPairs.length) {
+            let tracked = group.pairTrackers.get(getEntityId(entity));
+            if (!tracked) group.pairTrackers.set(getEntityId(entity), (tracked = new Set()));
+            if (group.type === eventType) tracked.add(targetId);
+            else if ((eventType === 'add' && group.type === 'remove') || (eventType === 'remove' && group.type === 'add')) tracked.delete(targetId);
+        }
+
+        const tracked = group.pairTrackers.get(getEntityId(entity));
+        const matches = group.pairs.every((pair) => {
+            const pairTarget = pair[$internal].target;
+            return pairTarget === '*'
+                ? !!tracked?.size
+                : tracked?.has(getEntityId(pairTarget as Entity));
+        });
+        if (group.logic === 'or') {
+            hasOr = true;
+            anyOr ||= matches;
+        } else if (!matches) return false;
+    }
+    return !hasOr || anyOr;
+}
+
+/** Notify tracking queries of a relation-pair event. */
+export function setPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    eventType: 'add' | 'remove' | 'change',
+    relationTrait: Trait,
+    target: Entity
+) {
+    const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
+    if (!instance) return;
+    for (const query of instance.trackingQueries) {
+        if (!query.trackingGroups.some((group) => group.pairs.length)) continue;
+        const match = query.checkPairTracking(world, entity, eventType, relationTrait, target);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
